SELECT ROUND(AVG(
    CAST(ABS(JULIANDAY(final_game) - JULIANDAY(debut)) AS REAL) / 365.0
), 2) AS avg_career_span_years
FROM player
WHERE debut IS NOT NULL AND final_game IS NOT NULL;

